define i1 @test_commuted_eq(i32 %x) {
  %v1 = tail call i32 @llvm.smax.i32(i32 %x, i32 -95)
  %v2 = tail call i32 @llvm.smin.i32(i32 %v1, i32 160)
  %cmp = icmp eq i32 %x, %v2
  ret i1 %cmp
}

